  9→import { usePhaseFilteredFloor } from '@/hooks/usePhaseFilteredFloor';
 10→import { useEditorTool } from '@/editor/useEditorTool';
 11→import { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
 12→import { formatSurveyorBearing, pointsToSurveyorBearing } from '@/geometry/bearing';
 13→import { TOOLS } from '@/editor/tools';
