492→                <text
493→                  x={0}
494→                  y={0}
495→                  textAnchor="middle"
496→                  dominantBaseline="middle"
497→                  fill="var(--color-text-secondary)"
498→                  fontSize={180}
499→                  fontFamily="var(--font-blueprint)"
500→                >
501→                  {roofHiddenByPhase ? 'Roof is hidden in the current phase view.' : 'Create a roof to edit roof geometry.'}
502→                </text>
503→              </g>
504→            )
505→          ) : modelTarget === 'truss' ? (
506→            viewMode === 'plan' ? (
507→              <>
508→                <TrussRenderer
509→                  floor={filteredFloor}
510→                  trussSystems={floorTrussSystems}
511→                  selectedId={selectedId}
512→                  selectedType={selectedType}
513→                />
514→                <TrussSelectionOverlay
515→                  floor={filteredFloor}
516→                  trussSystems={floorTrussSystems}
517→                  selectedId={selectedId}
518→                  selectedType={selectedType}
519→                  toolState={toolState}
520→                  zoom={viewport.zoom}
521→                />
522→                <TrussDrawOverlay
523→                  floor={filteredFloor}
524→                  activeTool={activeTool}
525→                  toolState={toolState}
526→                />
527→                {!floorTrussSystems.length && (
