529→                    <text
530→                      x={0}
531→                      y={0}
532→                      textAnchor="middle"
533→                      dominantBaseline="middle"
534→                      fill="var(--color-text-secondary)"
535→                      fontSize={180}
536→                      fontFamily="var(--font-blueprint)"
537→                    >
538→                      Draw a truss by selecting two support beams on the active floor.
539→                    </text>
540→                  </g>
541→                )}
542→              </>
543→            ) : floorTrussSystems.length ? (
544→              viewMode === 'truss_detail' ? (
545→                <TrussDetailRenderer
546→                  trussSystem={activeTrussContext.trussSystem}
547→                  trussInstanceId={activeTrussContext.trussInstanceId}
548→                />
