550→                <TrussSectionRenderer
551→                  project={filteredProject}
552→                  floor={filteredFloor}
553→                  activeSectionCutId={activeSectionCutId}
554→                />
555→              ) : (
556→                <g className="truss-empty-view">
557→                  <text
558→                    x={0}
559→                    y={0}
560→                    textAnchor="middle"
561→                    dominantBaseline="middle"
562→                    fill="var(--color-text-secondary)"
563→                    fontSize={180}
564→                    fontFamily="var(--font-blueprint)"
565→                  >
