596→                <StairRenderer stairs={filteredFloor.stairs || []} />
597→                <LandingRenderer landings={filteredFloor.landings || []} />
598→                <RailingRenderer railings={filteredFloor.railings || []} />
599→                <ColumnRenderer columns={filteredFloor.columns || []} />
