607→                <ClipboardPreviewLayer content={previewContent} />
608→                <RegionSelectionOverlay
609→                  marqueeBounds={marqueeBounds}
610→                  selectionBounds={regionSelection?.bounds || null}
611→                />
612→                <SelectionOverlay
613→                  selectedId={selectedId}
614→                  selectedType={selectedType}
615→                  floor={floor}
616→                  zoom={viewport.zoom}
617→                />
618→                <DimensionPreview toolState={toolState} activeTool={activeTool} />
619→                <WallPreview toolState={toolState} activeTool={activeTool} />
620→                <SlabPreview toolState={toolState} activeTool={activeTool} />
621→                <BeamPreview
622→                  toolState={toolState}
623→                  activeTool={activeTool}
624→                  columns={floor.columns || []}
625→                  floorLevel={getFloorElevation(floor)}
626→                />
627→                <StairPreview
628→                  toolState={toolState}
629→                  activeTool={activeTool}
630→                  floorId={floor.id}
631→                />
632→                <DoorWindowPreview
633→                  toolState={toolState}
634→                  activeTool={activeTool}
635→                  walls={floor.walls}
636→                />
637→                <SectionCutPreview toolState={toolState} activeTool={activeTool} />
638→                <RailingPreview toolState={toolState} activeTool={activeTool} />
639→                <ColumnPreview toolState={toolState} activeTool={activeTool} />
640→                <LandingPreview toolState={toolState} activeTool={activeTool} />
641→                <FixturePreview toolState={toolState} activeTool={activeTool} />
642→              </>
643→            ) : viewMode === 'section_view' ? (
644→              <SectionRenderer
645→                project={filteredProject}
646→                floor={filteredFloor}
647→                activeSectionCutId={activeSectionCutId}
648→              />
649→            ) : (
650→              <ElevationRenderer
651→                project={filteredProject}
652→                floor={filteredFloor}
653→                viewMode={viewMode}
654→                selectedId={selectedId}
655→                selectedType={selectedType}
656→              />
657→            )
658→          )}
659→        </g>
660→      </svg>
661→      <div className={styles.overlayControls}>
662→        <button
663→          type="button"
664→          className={styles.overlayBtn}
665→          onClick={handleResetCenterPoint}
