672→          type="button"
673→          className={styles.overlayBtn}
674→          onClick={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'canvas' })}
675→          title={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
676→          aria-label={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
677→        >
678→          {isCanvasMaximized ? <CollapseIcon /> : <ExpandIcon />}
679→        </button>
680→      </div>
681→      <div className={styles.statusBar}>
682→        <span>X: {Math.round(cursorPos.x)} mm</span>
683→        <span>Y: {Math.round(cursorPos.y)} mm</span>
684→        <span>Zoom: {zoomPercent}%</span>
685→        <span>View: {viewMode}</span>
686→        <span>Mode: {modelTarget}</span>
687→        <span>Tool: {displayedTool}</span>
688→        {activePhaseId && (
689→          <span>Phase: {(project.phases || []).find(p => p.id === activePhaseId)?.name || 'Unknown'} ({phaseViewMode})</span>
690→        )}
691→        {modelTarget === 'roof' && roofHiddenByPhase && <span>Roof: hidden by phase filter</span>}
692→        {modelTarget === 'truss' && !floorTrussSystems.length && <span>Trusses: none on active floor</span>}
693→        {modelTarget === 'truss' && activeTool === TOOLS.TRUSS_DRAW && <span>Draw: select two support beams</span>}
694→        {liveWallBearing && <span>Bearing: {liveWallBearing}</span>}
695→        {selectionCount > 0 && <span>Selection: {selectionCount} objects</span>}
696→        {modelTarget === 'roof' && viewMode === 'section_view' && !hasRoofSectionCut && <span>Section: add a floor section cut</span>}
697→        {modelTarget === 'truss' && viewMode === 'section_view' && !hasTrussSectionCut && <span>Section: add a floor section cut</span>}
698→        {modelTarget === 'floor' && pastePreview?.active && <span>Paste: click to place</span>}
699→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
700→      </div>
