  cursor: not-allowed;
}

.toolPaletteBtn:disabled:hover {
  background: transparent;
  border-color: transparent;
  color: var(--color-text-secondary);
}

.toolPaletteBtnActive {
  composes: toolPaletteBtn;
  background: var(--color-accent-subtle);
  color: var(--color-accent);
  border-color: rgba(13, 124, 102, 0.15);
}

.toolPaletteBtnActive:hover {
  background: rgba(13, 124, 102, 0.12);
}

.toolPaletteIcon {
  width: 18px;
  height: 18px;
  display: block;
}

/* Fixture palette */
.fixturePalette {
  display: flex;
  align-items: center;
  gap: 1px;
  padding: var(--space-xs) var(--space-sm);
  background: rgba(0, 0, 0, 0.02);
  border-radius: var(--radius-md);
  flex-shrink: 0;
}

.fixturePaletteLabel {
  font-size: 9px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--color-text-tertiary);
  margin-right: 4px;
  white-space: nowrap;
}

/* Toggle buttons (sidebar, properties, grid, snap) */
.toggleBtn {
  composes: btn;
  opacity: 0.5;
}

.toggleBtn.toggleActive {
  opacity: 1;
  background: var(--color-accent-subtle);
  color: var(--color-accent);
  border-color: rgba(13, 124, 102, 0.15);
}

.spacer {
  flex: 1;
}

/* Responsive breakpoints */
@media (max-width: 1100px) {
  .toolPalette {
    gap: 0;
  }
  .fixturePalette {
    gap: 0;
  }
  .toolPaletteBtn {
    width: 30px;
    height: 30px;
  }
  .segmentedBtn,
  .segmentedBtnActive {
    padding: 0 7px;
    font-size: 10px;
  }
}

@media (max-width: 900px) {
  .toolbar {
    gap: var(--space-xs);
    padding: 0 var(--space-sm);
  }
  .group {
    padding: 0 var(--space-xs);
  }
  .toolPalette {
    padding: 0 var(--space-xs);
  }
  .fixturePalette {
    padding: 0 var(--space-xs);
  }
  .fixturePaletteLabel {
    display: none;
  }
  .groupLabel {
    display: none;
  }
  .segmentedBtn,
  .segmentedBtnActive {
    padding: 0 5px;
    font-size: 10px;
    height: 26px;
  }
}

