.wrapper {
  position: relative;
  display: inline-flex;
}

.tooltip {
  position: absolute;
  bottom: calc(100% + 6px);
  left: 50%;
  transform: translateX(-50%) scale(0.95);
  opacity: 0;
  pointer-events: none;
  z-index: 100;

  background: rgba(30, 36, 51, 0.94);
  color: #F4F3F0;
  font-family: var(--font-ui);
  font-size: 11px;
  font-weight: 500;
  padding: 5px 8px;
  border-radius: var(--radius-sm);
  white-space: nowrap;
  box-shadow: var(--shadow-md);

  display: flex;
  align-items: center;
  gap: 6px;

  transition: opacity 0.15s ease, transform 0.15s ease;
}

.wrapper:hover .tooltip {
  opacity: 1;
  transform: translateX(-50%) scale(1);
  transition-delay: 0.4s;
}

.kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 16px;
  height: 16px;
  padding: 0 4px;
  border-radius: 3px;
  background: rgba(255, 255, 255, 0.12);
  border: 1px solid rgba(255, 255, 255, 0.08);
  font-family: var(--font-ui);
  font-size: 10px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.7);
  line-height: 1;
}

